(window.webpackJsonp=window.webpackJsonp||[]).push([[62],{689:function(n,r){n.exports='\x3c!-- \r\ntitle: NodeJS\r\nsort: \r\n--\x3e \r\n\r\n## NodeJS\r\n\r\n> `node.js`是基于chrome v8引擎的JS运行环境\r\n>\r\n> 前端开发环境、服务端编程语言\r\n\r\n### Npm\r\n\r\n> [npmjs](https://www.npmjs.com/)\r\n\r\n```powershell\r\nnode -v\r\nnode\t# 进入JS运行环境\r\n\r\nnpm -v\r\nnpm init\r\nnpm install [-g]\t# 全局安装\r\n# 换源\r\nnpm config set registry https://registry.npm.taobao.org\r\n# 发布包时换回原来的源\r\nnpm config set registry https://registry.npmjs.org\r\n# 发布插件\r\nnpm adduser | npm publish\r\n# 删除\r\nnpm unpublish --force\r\n```\r\n\r\n  ### Yarn\r\n\r\n  > `npm i yarn -g`\r\n  >\r\n  > 弥补了npm的一些缺陷\r\n  >\r\n  > [中文文档](https://yarn.bootcss.com/)\r\n\r\n  ```powershell\r\nnpm i yarn@1.22.0 -g \t# 安装特定版本\r\nnpm upgrade yarn -g\t\t# 更新\r\n  \r\nyarn config set registry https://registry.npm.taobao.org\r\n  \r\nyarn -v\r\n# 初始化项目\r\nyarn init\r\nyarn isntall\r\nyarn add/remove # 添加依赖包\r\nyarn publish\r\nyarn run\r\n  ```\r\n\r\n  > 搭建环境\r\n\r\n  ```powershell\r\nyarn init\r\nyarn add xx --save\t# 添加新插件\r\nyarn install\t\t# 拉取旧插件\r\n\r\nyarn login\t\t\t# 登录\r\nyarn logout\t\t\t# 登出\r\n  ```\r\n\r\n  > 编辑Package\r\n\r\n  ```json\r\n    "scripts": {\r\n      "ver": "npm -v"\r\n    },\r\n  \r\n  // yarn run server\r\n  ```\r\n'}}]);